refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"));
image = imresize(image, [240 320]);
points = [55 80; 105 100; 155 120; 205 140; 255 160];
line = imfitline(points);
imshow(image);
plot(points(:, 1), points(:, 2), "ko");
plot([line(3) - 120 * line(1) line(3) + 120 * line(1)], [line(4) - 120 * line(2) line(4) + 120 * line(2)], "r-");
